"""
Comprehensive Payload Library for Active Scanning.
Covers 15+ vulnerability categories with 500+ payloads.
Inspired by sqlmap, xray, nuclei, and Burp Suite payload collections.
"""
from dataclasses import dataclass, field
from enum import Enum
from typing import List, Dict, Optional


class PayloadCategory(str, Enum):
    SQLI = "sqli"
    XSS = "xss"
    CMD_INJECTION = "cmd_injection"
    PATH_TRAVERSAL = "path_traversal"
    SSTI = "ssti"
    XXE = "xxe"
    SSRF = "ssrf"
    LDAP = "ldap"
    NOSQL = "nosql"
    FILE_UPLOAD = "file_upload"
    CRLF = "crlf"
    HPP = "hpp"
    OPEN_REDIRECT = "open_redirect"
    DESERIALIZATION = "deserialization"
    JWT = "jwt"
    XPATH = "xpath"
    HEADER_INJECTION = "header_injection"


class DBMS(str, Enum):
    MYSQL = "mysql"
    POSTGRESQL = "postgresql"
    MSSQL = "mssql"
    ORACLE = "oracle"
    SQLITE = "sqlite"
    GENERIC = "generic"


class XSSContext(str, Enum):
    HTML = "html"
    ATTRIBUTE = "attribute"
    JAVASCRIPT = "javascript"
    URL = "url"
    CSS = "css"
    SVG = "svg"


@dataclass
class Payload:
    value: str
    category: PayloadCategory
    sub_category: str = ""
    dbms: Optional[DBMS] = None
    context: Optional[XSSContext] = None
    description: str = ""
    risk_level: str = "medium"


