def get_payloads_by_category(category: PayloadCategory) -> List[Payload]:
    return ALL_PAYLOADS.get(category, [])


def get_payloads_by_sub_category(category: PayloadCategory, sub_category: str) -> List[Payload]:
    return [p for p in get_payloads_by_category(category) if p.sub_category == sub_category]


def get_payloads_by_dbms(category: PayloadCategory, dbms: DBMS) -> List[Payload]:
    return [p for p in get_payloads_by_category(category) if p.dbms in (dbms, DBMS.GENERIC)]


def get_payloads_by_context(category: PayloadCategory, context: XSSContext) -> List[Payload]:
    return [p for p in get_payloads_by_category(category) if p.context == context]


def get_payloads_by_risk(category: PayloadCategory, risk_level: str) -> List[Payload]:
    return [p for p in get_payloads_by_category(category) if p.risk_level == risk_level]


def get_all_payload_values(category: PayloadCategory) -> List[str]:
    return [p.value for p in get_payloads_by_category(category)]


def get_payload_count() -> Dict[str, int]:
    return {cat.value: len(payloads) for cat, payloads in ALL_PAYLOADS.items()}


def get_total_payload_count() -> int:
    return sum(len(payloads) for payloads in ALL_PAYLOADS.values())


def search_payloads(keyword: str) -> List[Payload]:
    results = []
    keyword_lower = keyword.lower()
    for payloads in ALL_PAYLOADS.values():
        for p in payloads:
            if keyword_lower in p.value.lower() or keyword_lower in p.description.lower():
                results.append(p)
    return results


def get_payload_categories() -> List[Dict[str, str]]:
    return [
        {
            "category": cat.value,
            "name": cat.name,
            "count": len(ALL_PAYLOADS[cat]),
        }
        for cat in PayloadCategory
    ]